var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>반역자의 낙인을 새긴 여인이 동토에서 오리라.</color>","JPN":" <color=#ffd34c>反逆者の烙印を押された女が凍土より到来するであろう。</color>","ENG":"<color=#ffd34c>A woman with the brand of a traitor will come to the gelid lands.</color>","TWN":" <color=#ffd34c>身上有叛徒印記的女子從凍土而來。</color>"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>여인은 악마에게 영혼을 바치고, 모든 생명을 죽일 힘을 얻을지니.</color>","JPN":" <color=#ffd34c>女は悪魔に魂を捧げ、すべての生命を殺す力を得る。</color>","ENG":"<color=#ffd34c>She will give her soul to the devil and gain the strength to kill all life.</color>","TWN":" <color=#ffd34c>女子將靈魂獻給魔鬼，獲取足以滅掉所有性命的能力。</color>"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>세계는 인류의 종말을 대가로 그녀를 택하리라.</color>","JPN":" <color=#ffd34c>世界は人類の終焉と引き換えに彼女を選ぶだろう。</color>","ENG":"<color=#ffd34c>The world will choose her at the cost of humanity's end.</color>","TWN":" <color=#ffd34c>世界以人類的滅亡作為選擇那個女子的代價。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"땅이 흔들리고 있어요. 어제처럼.","JPN":"地面が揺れています。昨日と同じく。","ENG":"The ground is shaking. Just like yesterday.","TWN":"地震！跟昨天一樣。"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"또 지진이라니. 근처에서 눈사태라도 난 건가?","JPN":"また地震か。近くで雪崩でも起きたか？","ENG":"Another earthquake? Is there an avalanche nearby?","TWN":"又地震，是附近發生雪崩嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_QM","text":{"KOREA":"재판 중에는 다들 조용히.","JPN":"裁判中なので皆ご静粛に。","ENG":"Order in the court!","TWN":"審判中大家肅靜。"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그럼… 죄인들의 항변을 들어보도록 하지.","JPN":"それでは……罪人たちの抗弁を聞くとします。","ENG":"Now... let us hear the pleas of the sinners.","TWN":"接下來…來聽聽罪人的辯護。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARD_ROOT_NPC_NULL","text":{"KOREA":"아아, 존경하는 제사장 멀린이여.","JPN":"ああ、尊敬する司祭長マーリン様。","ENG":"Aah, High Priest Merlin.","TWN":"喔喔～敬重的梅林祭司長。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARD_ROOT_NPC_NULL","text":{"KOREA":"난 죄를 짓지 않았습니다. 그저 한 남자로서 한 여자를 사랑했을 뿐.","JPN":"私は罪など犯しておりません。ただ一人の男として、とある女性を愛したまで。","ENG":"I have not sinned. I am merely a man who loved a woman.","TWN":"我沒有犯罪，我只是身為一個男人，深愛一個女人而已。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래, 사랑에는 죄가 없어.","JPN":"ええ、誰かを愛することは罪ではないわ。","ENG":"Yes, love is no sin.","TWN":"沒錯，愛何罪之有。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"사랑이란 감정은 무척이나 자유롭지. 그 감정의 옳고 그름을 관철하는 게 우리의 이성이고.","JPN":"誰かを愛する気持ちは無秩序で自由。その気持ちが正しいかどうかを判断し、制御するのが我々が持つ理性よ。","ENG":"Also, the feeling of love is free. It is up to our reasoning to determine whether that emotion is right or wrong.","TWN":"愛是自由的，至於那份愛是對的還是錯的，取決於我們的理性。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"근데 임자 있는 여자는 넘보지 말라고, 내가 가르치지 않았던가?","JPN":"でも、すでに誰かのものとなった女性を欲してはならないと、アタシは言ったはず。","ENG":"Have I not taught you to not love a married woman?","TWN":"但我沒教過你，不要對有夫之婦有非分之想嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARD_ROOT_NPC_NULL","text":{"KOREA":"한평생 그토록 절실한 사랑을 느껴본 적이 없건만. 그녀가 기혼자였단 진실은 그야말로 비극이지요.","JPN":"私は人生の中で、これほどまで真剣に誰かを愛したことはない。しかしその相手が既婚者だったことは、悲劇としか言いようがないのです。","ENG":"I have never felt so desperately in love before. And it is truly tragic that she is already married.","TWN":"我此生從未有過如此刻骨銘心的愛情，但她卻是個有夫之婦，此乃人間悲劇。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARD_ROOT_NPC_NULL","text":{"KOREA":"허나 난 과실처럼 달콤한 그녀의 호의를 뿌리칠 수가 없었을 뿐이오!","JPN":"私は甘い果実のような彼女からの好意に、逆らえなかっただけ！","ENG":"However, I couldn't resist her kindness, sweet as fruit!","TWN":"我只是個凡夫俗子，無法掙脫她如果實般甜美的誘惑！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"뭐? 이게 어디서 혼자 슬쩍 발을 빼?","JPN":"はあ？　全部私の責任にしようとしてるの？","ENG":"What? How dare you try to blame it all on me?","TWN":"什麼？你現在是想自己脫身嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"내가 남편이 있단 걸 알면서도 계속 꼬셔댄 건 당신이잖아!","JPN":"私に旦那がいるって知っていても誘惑してきたのは、あなたでしょ！","ENG":"You knew I had a husband! Yet, you kept flirting with me!","TWN":"你明知道我是有夫之婦，還一直來糾纏我！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARD_ROOT_NPC_NULL","text":{"KOREA":"내 기억에도 없는 소릴 들먹이다니. 그대는 거짓말쟁이나 마녀가 틀림없군!","JPN":"私の記憶には一切ないことを言い出すとは、君は嘘つきか？　あるいは魔女であるな！","ENG":"I do not remember any of the sort. You must be a liar or a witch!","TWN":"你在胡說八道什麼！我看你不是說謊成性就是魔女！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"멀린님! 저 남자가 날 먼저 유혹했어요! 난 계속 거절하려 했다고요!","JPN":"マーリン様！　あの男が先に私に色目を使ってきました。私は必死に断ろうとしましたよ！","ENG":"Ms. Merlin! That man seduced me first! I kept trying to refuse!","TWN":"梅林祭司長！是他先勾引我的！我一直拒絕他！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"흐음…","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"얘길 들어보니, 아무래도 두 사람은 서로를 절반만큼 사랑한 것 같네.","JPN":"二人の話を聞くかぎり、どうやらあなたたちはお互いに半分程度の愛をしたようね。","ENG":"After hearing you both, it seems that you both only loved each other half as much.","TWN":"聽完雙方的說詞，應該是有彼此喜歡。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"두 사람 모두 반으로 갈라서 나눠갖는 건 어때?","JPN":"よって、あなたたち二人を半分ずつ分け合ってもらうというのはどうかしら？","ENG":"So, how about splitting you two in half for each other?","TWN":"不如就二人各承擔一半的刑罰吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARD_ROOT_NPC_NULL","text":{"KOREA":"히익!","JPN":"ひいっ！","ENG":"Eeeek!","TWN":"什麼！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"너무하세요, 제사장님!","JPN":"それはあんまりです、司祭長様！","ENG":"But that is too harsh, High Priest!","TWN":"祭司長，這不公平！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"다른 남잘 사랑한 게 죽을 죄인 건가요?","JPN":"旦那以外の男を愛したことが、死ぬほどの罪なんでしょうか？","ENG":"Is loving another man a mortal sin?","TWN":"愛上其他男人是死罪嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"사랑은 죄가 아니야. 한 사람만을 사랑하겠다는 결혼 서약을 어긴 게 잘못이지.","JPN":"その気持ち自体は罪ではないわ。罪なのは一人の男だけを愛するという誓いを破ったことよ。","ENG":"Love is not a sin. But it is your fault for breaking your vow to only love your husband.","TWN":"愛本身沒有犯法，錯的是你違背結婚時許下的承諾。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"평생 한 사람만 사랑하라는 규칙이 잘못된 건 아니고요?","JPN":"一生一人の相手だけを愛し続けろなんていう掟の方が、間違っているんじゃないの？","ENG":"Then isn't the rule that one must love only one person in their life wrong?","TWN":"一輩子只能愛一個人，這個諾言本身就有問題的吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIFE_ROOT_NPC_NULL","text":{"KOREA":"허구한날 땅이 뒤틀리고 마물이 들이닥치는 세상에서 그깟 결혼 서약이 무슨 대수라고!","JPN":"絶えず地面は揺れて、魔物にまで襲われるような世界で、婚姻の誓いが、そんなに重要ですか！？","ENG":"In a world where the ground shakes and monsters appear, what value does a marriage vow hold?!","TWN":"在長年冰凍、怪物會突然出現的世界裡，婚約還有什麼重要的呢！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};